import React, { useState,useEffect } from "react";
import "./style.css";
import { useNavigate } from "react-router-dom";

function FoodTracking(){
    const navigate=useNavigate();
    const [foodType,setFoodType]=useState("");
    const [foods,setFoods]=useState([]);
    const [foodEntries,setFoodEntries]=useState([{food:"",foosType:"",quantity:""}]);

    useEffect(()=>{
        getFoods();
    },[]);

    function updateFoodEntry(index,field,value){
        const updated=[...foodEntries];
        updated[index][field]=value;
        setFoodEntries(updated);
    }

    async function getFoods() {
        try{
            const response=await fetch("http://localhost:5000/foods");
            const data=await response.json();
            console.log(data);
            setFoods(data);
            
        }
        catch(err){
            console.log(err);
        }
    }

    const Homemade=()=>{
        
        /*return(
            <>
                <label htmlFor="homemadeFood">Select Food</label>
                <div id="homemadeSection1">
                
                {
                    
                    foodEntries.map((entry,index)=>(
                        <div key={index}>
                            <select value={entry.food} id={`homemadeFood-${index}`} style={{width: '250px'}} onChange={(e)=>updateFoodEntry(index,"food",e.target.value)}>
                                <option value="">-- Choose Food --</option>
                           
                            
                            {
                                foods.map((item,index)=>
                                    <option key={index} value={item.food_name}>{item.food_name}</option>
                                )
                            }
                        
                            </select>
                            <input id={`quantity-${index}`} name="quantity" value={entry.quantity} type="text" placeholder={'Enter Quantity'} onChange={(e)=>updateFoodEntry(index,"quantity",e.target.value)}/>
                    
                        </div>
                        
                    ))
                }
                  </div>  
            </>
        );*/
    }

   

    function goToDashboard(e){
        e.preventDefault();
        console.log(foodEntries);
        navigate('/dashboard');
    }

    function addFoodHandle(){
        setFoodEntries([...foodEntries,{food:"",quantity:""}]);
        
    }

    function AddFood(){
        return (
            <>
               
                <div id="homemadeSection1">
                
                {
                    
                    foodEntries.map((entry,index)=>(
                        <div key={index}>
                            <label htmlFor="foodType">Choose Food Type</label>
                            <select id="foodType" style={{width: '250px'}} onChange={(e)=>updateFoodEntry(index,"foodType",e.target.value)}>
                                <option value="">-- Select --</option>
                                <option value="homemade">Homemade Food</option>
                                <option value="packaged">Packaged Food</option>
                                <option value="fruits">Fruits</option>
                                <option value="vegetables">Vegetables</option>
                                <option value="rice&grains">Rice and Grains</option>
                                <option value="dairyproducts">Dairy Products</option>
                                <option value="snaks&fastfood">Snacks and Fastfood</option>
                                <option value="Beverages">Beverages</option>
                            </select>
                            <select value={entry.food} id={`homemadeFood-${index}`} style={{width: '250px'}} onChange={(e)=>updateFoodEntry(index,"food",e.target.value)}>
                                <option value="">-- Choose Food --</option>
                           
                            
                            {
                                foods.map((item,index)=>
                                    <option key={index} value={item.food_name}>{item.food_name}</option>
                                )
                            }
                        
                            </select>
                            <input id={`quantity-${index}`} name="quantity" value={entry.quantity} type="text" placeholder={'Enter Quantity'} onChange={(e)=>updateFoodEntry(index,"quantity",e.target.value)}/>
                    
                        </div>
                        
                    ))
                }
                  </div>  
            
            </>
        );
    }

    return(
        <>
            <div className="container">

            <h1>Food Tracker</h1>
            <AddFood/>
            <form >
                <button type="button" onClick={addFoodHandle}>Add Food</button>
                <button type="submit" onClick={goToDashboard}>Submit</button>
            </form>
            </div>
        </>
    );
}

export default FoodTracking;
